st.title("🌱 당신을 위한 깊은 위로, 50가지 마음 처방전")
user_input = st.text_input("지금 어떤 기분이 드시나요?")

if user_input:
    found = False
    for category, data in emotion_data.items():
        if any(key in user_input for key in data["keywords"]):
            # 매번 새로운 위로 문구
            random_comfort = random.choice(data["공감_옵션"])
            
            st.subheader(f"💡 [{category}] 마음을 위한 다정한 위로")
            st.markdown(f"**{random_comfort}**")
            st.write("---")
            st.write("### 🧘 당신을 위한 정성스러운 처방:")
            for i, action in enumerate(data["처방"], 1):
                st.write(f"{i}. {action}")
            found = True
            break
            
    if not found:
        st.write("당신의 마음을 더 자세히 알고 싶어요. 지금 어떤 기분인가요?")
